{
  "recipe": {
    "recipe_format_version": "0.2",
    "id": "rcp_evidence-enriched",
    "version": 1,
    "status": "promoted",
    "concern": "evidence-and-conflicts",
    "applies_to": {
      "source_type": "json",
      "shape_signature": "json(claim:string,confidence:number,dimensions:array,id:string,label:string,source:object)"
    },
    "defaults": {
      "provenance": "EXTRACTED"
    },
    "authoring": {
      "authored_by": "data-specialist",
      "sample_basis": "EURail evidence ledger records (nested source{} object)."
    },
    "mappings": [
      {
        "id": "evidence",
        "project_to": "node",
        "label": "Evidence",
        "match": {
          "unit_kind": "record"
        },
        "identity": {
          "scheme": "deterministic",
          "from": [
            "field:id"
          ],
          "normalize": [
            "trim"
          ]
        },
        "properties": [
          {
            "name": "claim",
            "value_from": "field:claim"
          },
          {
            "name": "confidence",
            "value_from": "field:confidence"
          },
          {
            "name": "label",
            "value_from": "field:label"
          },
          {
            "name": "dimensions",
            "value_from": "field:dimensions"
          }
        ]
      },
      {
        "id": "claim_source",
        "project_to": "node",
        "label": "ClaimSource",
        "match": {
          "unit_kind": "record"
        },
        "identity": {
          "scheme": "deterministic",
          "from": [
            "field:source.url"
          ],
          "normalize": [
            "trim"
          ]
        },
        "properties": [
          {
            "name": "name",
            "value_from": "field:source.name"
          },
          {
            "name": "publication_date",
            "value_from": "field:source.publication_date"
          }
        ]
      },
      {
        "id": "from_source",
        "project_to": "edge",
        "type": "FROM_SOURCE",
        "match": {
          "unit_kind": "record"
        },
        "from": {
          "node_rule": "evidence"
        },
        "to": {
          "node_rule": "claim_source",
          "resolve_by": "identity"
        }
      },
      {
        "id": "publisher",
        "project_to": "node",
        "label": "Publisher",
        "match": {
          "unit_kind": "record"
        },
        "identity": {
          "scheme": "deterministic",
          "from": [
            "field:source.url"
          ],
          "normalize": [
            "trim"
          ],
          "transform": "host"
        }
      },
      {
        "id": "published_by",
        "project_to": "edge",
        "type": "PUBLISHED_BY",
        "match": {
          "unit_kind": "record"
        },
        "from": {
          "node_rule": "claim_source"
        },
        "to": {
          "node_rule": "publisher",
          "resolve_by": "identity"
        }
      },
      {
        "id": "tag",
        "project_to": "node",
        "label": "Tag",
        "match": {
          "unit_kind": "record"
        },
        "from_each": "field:dimensions",
        "identity": {
          "scheme": "deterministic",
          "from": [
            "field:dimensions"
          ],
          "normalize": [
            "trim",
            "casefold"
          ]
        },
        "edge_to_each": {
          "type": "HAS_DIMENSION",
          "from_node_rule": "evidence"
        }
      }
    ],
    "extractions": [
      {
        "id": "claim_entities",
        "from": "field:claim",
        "ontology": {
          "mode": "strict",
          "domain": "rail travel and tourism",
          "entity_types": [
            {
              "name": "Person",
              "description": "A named individual."
            },
            {
              "name": "Organization",
              "description": "A company, agency, or operator."
            },
            {
              "name": "Product",
              "description": "A named product, pass, or service."
            },
            {
              "name": "Place",
              "description": "A named city, country, or location."
            }
          ],
          "relationship_types": [
            {
              "name": "OPERATES",
              "source": "Organization",
              "target": "Product"
            },
            {
              "name": "LOCATED_IN",
              "source": "Organization",
              "target": "Place"
            }
          ]
        },
        "resolution": {
          "canonical": true,
          "merge_threshold": 0.92,
          "candidate_threshold": 0.85
        },
        "link": {
          "type": "MENTIONS",
          "from_node_rule": "evidence"
        }
      }
    ],
    "similarities": [
      {
        "id": "claim_similarity",
        "from": "field:claim",
        "node_rule": "evidence",
        "edge_type": "SIMILAR_TO",
        "top_k": 5,
        "min_score": 0.5
      }
    ]
  }
}

{
  "content": "[{\"id\": \"ev-1\", \"claim\": \"Eurail B.V. operates the Eurail Global Pass across Europe.\", \"confidence\": 0.9, \"label\": \"product-coverage\", \"dimensions\": [\"coverage\", \"passes\"], \"source\": {\"url\": \"https://www.eurail.com/en/passes/global-pass\", \"name\": \"Eurail \\u2014 Global Pass\", \"publication_date\": \"2026-01-10\"}}, {\"id\": \"ev-2\", \"claim\": \"eurail.com lists the Global Pass as valid in 33 countries.\", \"confidence\": 0.8, \"label\": \"product-coverage\", \"dimensions\": [\"coverage\"], \"source\": {\"url\": \"https://eurail.com/en/about\", \"name\": \"Eurail \\u2014 About\", \"publication_date\": \"2026-02-02\"}}]",
  "source_type": "json",
  "recipe_id": "rcp_evidence-enriched"
}

